const hamMenu=document.getElementById("hamMenu"),offScreenNav=document.getElementById("offScreenNav"),handleHamAnimations=()=>{hamMenu.classList.toggle("animate"),offScreenNav.classList.toggle("show")};hamMenu.addEventListener("click",handleHamAnimations),offScreenNav.addEventListener("click",handleHamAnimations);const particleBoard=document.querySelector(".particle-board"),config={particleCount:200};for(let e=0;e<config.particleCount;e++)createParticle(),positionParticle();function createParticle(){let e=document.createElement("div");e.classList.add("particle"),particleBoard.appendChild(e)}function positionParticle(e){let t=document.querySelectorAll(".particle");for(let e=0;e<t.length/2;e++)t[e].classList.add("mobile");t.forEach((e=>{let t=Math.floor(-1400*Math.random()+700);e.style.top=`${t}%`;let n=Math.floor(-1400*Math.random()+700);e.style.left=`${n}%`;let o=Math.floor(50*Math.random()),a=Math.floor(1*Math.random());e.style.animation=`particles ${o}s ${a}s ease infinite`}))}const projectData=[{name:"Online Registration Form",description:"I used HTML and CSS to create a fully responsive registration form for users attending a conference.",githubLink:"",livedemoLink:"",thumbnail:"./assets/proj3.png"},{name:"Interactive Photo Gallery",description:"This photo gallery app uses JavaScript to search/filter through photos as well as to show a larger version once a photo is clicked. I used CSS Gird to layout the photo gallery.",githubLink:"",livedemoLink:"",thumbnail:"./assets/proj5.png"},{name:"Gameshow App",description:"I used my knowledge of JavaScript to build out a fun, interactive game. Users have to guess the random word up on the screen but only get 5 attempts to guess the word before losing.",githubLink:"",livedemoLink:"",thumbnail:"./assets/proj6.png"},{name:"WebApp Dashboard",description:"This well-structured dashboard was built using CSS grid and flex-box. I used the Chart.js plugin to display data onto the dashboard. ",githubLink:"",livedemoLink:"",thumbnail:"./assets/proj7.png"},{name:"Employee Directory (API)",description:"Connecting to the randomuser API, I was able to generate a webpage with data from an API using fetch.",githubLink:"",livedemoLink:"",thumbnail:"./assets/proj8.png"}];function createProject(e){const t=document.getElementById("contentImage"),n=document.getElementById("projectInfo"),o=n.querySelector("h4"),a=n.querySelector("p"),r=n.querySelector("a.repo"),i=n.querySelector("a.live");t.src=e.thumbnail,o.textContent=e.name,a.textContent=e.description,r.setAttribute("href",e.githubLink),i.setAttribute("href",e.livedemoLink)}createProject(projectData[0]);let currentIndex=0;const projectCarousel=document.getElementById("projectCarousel");function handleCarouselSwitching(e){const t=document.querySelector(".project-carousel i.fa-angle-left"),n=document.querySelector(".project-carousel i.fa-angle-right");e.target===t?(0===currentIndex?currentIndex=projectData.length-1:currentIndex--,createProject(projectData[currentIndex])):e.target===n&&(currentIndex===projectData.length-1?currentIndex=0:currentIndex++,createProject(projectData[currentIndex]))}projectCarousel.addEventListener("click",(e=>{handleCarouselSwitching(e)}));